def calculate_electricity_bill(input_string):
    units = []
    parts = input_string.split(',')

    for part in parts:
        if "Units:" in part:
            value = part.split(":")[1].strip()
            if value.isdigit():
                units.append(int(value))

    total_units = 0
    for unit in units:
        total_units += unit

    total_bill = 0
    remaining_units = total_units

    if remaining_units > 0:
        if remaining_units >= 100:
            total_bill += 100 * 0.50
            remaining_units -= 100
        else:
            total_bill += remaining_units * 0.50
            remaining_units = 0

    if remaining_units > 0:
        if remaining_units >= 100:
            total_bill += 100 * 0.75
            remaining_units -= 100
        else:
            total_bill += remaining_units * 0.75
            remaining_units = 0

    if remaining_units > 0:
        if remaining_units >= 100:
            total_bill += 100 * 1.00
            remaining_units -= 100
        else:
            total_bill += remaining_units * 1.00
            remaining_units = 0

    if remaining_units > 0:
        total_bill += remaining_units * 1.50

    return total_units, total_bill

input_string = input()
total_units, total_bill = calculate_electricity_bill(input_string)

print("Total Units Consumed:", total_units)
print(f"Total Bill: ${total_bill:.2f}")
